//

var loadExternalScript = (scriptUrl, callback) => {
  var script = document.createElement("script");
  script.src = scriptUrl;

  script.onload = () => {
    console.log(scriptUrl + " loaded, ready for action");

    if (callback) {
      callback(scriptUrl, true); // succeed
    }
  };

  script.onerror = e => {
    console.log(scriptUrl + " failed to load !");

    if (callback) {
      callback(scriptUrl, false); // failed
    }
  };

  document.head.appendChild(script);
};

//

module.exports = loadExternalScript;
